#include <vector>
#include <string>
#include <algorithm>
#include <regex>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> validCodes;
    vector<pair<int, string>> businessOrder = {
        {0, "electronics"},
        {1, "grocery"},
        {2, "pharmacy"},
        {3, "restaurant"}
    };

    for (size_t i = 0; i < code.size(); ++i) {
        // Check if code is valid (non-empty and only alphanumeric + underscore)
        bool codeValid = !code[i].empty();
        if (codeValid) {
            codeValid = regex_match(code[i], regex("^[a-zA-Z0-9_]+$"));
        }

        // Check if businessLine is valid
        bool businessValid = false;
        int businessPriority = -1;
        for (const auto& pair : businessOrder) {
            if (businessLine[i] == pair.second) {
                businessValid = true;
                businessPriority = pair.first;
                break;
            }
        }

        // Check if isActive is true
        bool activeValid = isActive[i];

        if (codeValid && businessValid && activeValid) {
            validCodes.push_back(code[i]);
        }
    }

    // Custom sort
    auto getBusinessPriority = [&businessOrder](const string& business) {
        for (const auto& pair : businessOrder) {
            if (business == pair.second) {
                return pair.first;
            }
        }
        return -1;
    };

    vector<pair<int, string>> toSort;
    for (const string& code : validCodes) {
        size_t index = &code - &validCodes[0];
        string business = businessLine[index];
        int priority = getBusinessPriority(business);
        toSort.emplace_back(priority, code);
    }

    sort(toSort.begin(), toSort.end(), [](const pair<int, string>& a, const pair<int, string>& b) {
        if (a.first != b.first) {
            return a.first < b.first;
        } else {
            return a.second < b.second;
        }
    });

    validCodes.clear();
    for (const auto& pair : toSort) {
        validCodes.push_back(pair.second);
    }

    return validCodes;
}

