public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    List<String> validCodes = new ArrayList<>();
    String[] businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    for (int i = 0; i < code.length; i++) {
        // Check if code is valid (non-empty and only alphanumeric + underscore)
        boolean codeValid = code[i] != null && !code[i].isEmpty();
        if (codeValid) {
            codeValid = Pattern.matches("^[a-zA-Z0-9_]+$", code[i]);
        }

        // Check if businessLine is valid
        boolean businessValid = false;
        int businessPriority = -1;
        for (int j = 0; j < businessOrder.length; j++) {
            if (businessLine[i].equals(businessOrder[j])) {
                businessValid = true;
                businessPriority = j;
                break;
            }
        }

        // Check if isActive is true
        boolean activeValid = isActive[i];

        if (codeValid && businessValid && activeValid) {
            validCodes.add(code[i]);
        }
    }

    // Custom sort
    Collections.sort(validCodes, new Comparator<String>() {
        @Override
        public int compare(String a, String b) {
            int aIndex = -1;
            int bIndex = -1;
            for (int i = 0; i < businessOrder.length; i++) {
                if (businessLine[getIndex(code, a)].equals(businessOrder[i])) {
                    aIndex = i;
                }
                if (businessLine[getIndex(code, b)].equals(businessOrder[i])) {
                    bIndex = i;
                }
            }
            if (aIndex != bIndex) {
                return Integer.compare(aIndex, bIndex);
            } else {
                return a.compareTo(b);
            }
        }
    });

    return validCodes.toArray(new String[0]);
}

private static int getIndex(String[] code, String target) {
    for (int i = 0; i < code.length; i++) {
        if (code[i].equals(target)) {
            return i;
        }
    }
    return -1;
}
