                businessPriority = j;
                break;
            }
        }

        // Check if isActive is true
        boolean activeValid = isActive[i];

        if (codeValid && businessValid && activeValid) {
            validCodes.add(code[i]);
        }
    }

    // Sort the valid codes
    Collections.sort(validCodes, new Comparator<String>() {
        @Override
        public int compare(String a, String b) {
            int aIndex = -1;
            int bIndex = -1;
            for (int i = 0; i < validBusinessLines.length; i++) {
                if (validBusinessLines[i].equals(businessLine[getIndex(code, a)])) {
                    aIndex = i;
